45	        role: s.role ?? 'viewer',
46	        color: `var(${participantColorToken(idx)})`,
47	        sessionStartedAt: Date.now(),
48	      }));
49	    setParticipants(next);
50	  }, []);
51	
52	  const connect = useCallback(() => {
53	    if (!mountedRef.current) return;
54	
55	    const p = window.location.protocol === 'https:' ? 'wss' : 'ws';
56	    const url = `${p}://${window.location.host}/api/models/${encodeURIComponent(modelId)}/collab`;
57	
58	    const provider = new WebsocketProvider(url, modelId, ydocRef.current, {
59	      connect: true,
60	      resyncInterval: -1,
