82	      setConnected(false);
83	      if (!mountedRef.current) return;
84	      const attempt = reconnectAttemptsRef.current + 1;
85	      reconnectAttemptsRef.current = attempt;
86	      if (attempt > MAX_RECONNECT_ATTEMPTS) return;
87	      const base = Math.min(250 * 2 ** (attempt - 1), 8000);
88	      const jitter = base * 0.2 * (Math.random() * 2 - 1);
89	      setTimeout(
90	        () => {
91	          if (!mountedRef.current) return;
92	          providerRef.current?.destroy();
93	          connect();
94	        },
95	        Math.max(0, Math.round(base + jitter)),
96	      );
97	    });
98	  }, [modelId, userId, role, updateParticipants]);
99	
100	  useEffect(() => {
101	    mountedRef.current = true;
102	    connect();
103	    return () => {
104	      mountedRef.current = false;
105	      providerRef.current?.destroy();
106	      providerRef.current = null;
