118	    () => ({
119	      ydoc: ydocRef.current,
120	      awareness: providerRef.current?.awareness ?? null,
121	      participants,
122	      localUserId: userId,
123	      broadcastSelection,
124	      connected,
125	    }),
126	    [participants, userId, broadcastSelection, connected],
127	  );
128	
129	  return <CollabContext.Provider value={value}>{children}</CollabContext.Provider>;
130	}
131	
132	export function useCollab(): CollabContextValue {
133	  const ctx = React.useContext(CollabContext);
134	  if (!ctx) throw new Error('useCollab must be used within CollabProvider');
135	  return ctx;
136	}
